mapper.select:
select sc.scId as scid, sc.scStudentId as scstudentid, sc.scTermId as sctermid, sc.scClassId as scclassid, sc.scCourseId as sccourseid, sc.scTeacherId as scteacherid, sc.scScore as scscore, sc.scStatus as scstatus, sc.scCreateDate as sccreatedate, s.sNo as sno, s.sName as sname, c.cName as cname, cr.crName as crname, yt.yAll as yall, t.tName as tname from scoreinfo sc left join studentinfo s on sc.scStudentId = s.sId left join classinfo c on sc.scClassId = c.cId left join courseinfo cr on sc.scCourseId = cr.crId left join yearterm yt on sc.scTermId = yt.yId left join teacherinfo t on sc.scTeacherId = t.tId where sc.scTeacherId = #{teacherid}
and sc.scTermId = #{obj.sctermid}
and sc.scClassId = #{obj.scclassid}
and sc.scCourseId = #{obj.sccourseid}
and sc.scStatus = #{obj.scstatus}
and ( s.sNo like concat('%', #{obj.qkey}, '%') or s.sName like concat('%', #{obj.qkey}, '%') )
order by sc.scId desc

select count(1)
from teaching
where tcTeacherId = #{teacherid}
  and tcTermId = #{sctermid}
  and tcClassId = #{scclassid}
  and tcCourseId = #{sccourseid}
